import{f as e,n as r}from"./chunks/theme.qLEC-07W.js";import{c as o,Q as s,j as n,m as a}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Settings","description":"","frontmatter":{},"headers":[],"relativePath":"guide/portal/settings.md","filePath":"guide/portal/settings.md","lastUpdated":1779094756000}'),i={name:"guide/portal/settings.md"};function d(l,t,g,c,h,u){return s(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p>The <strong>Settings</strong> page is the central control panel for your customer organisation. It is where you configure authentication, manage service accounts, set up webhooks, and define which user attributes are required for your team.</p><p>Settings are split across five tabs.</p><h2 id="organization" tabindex="-1">Organization <a class="header-anchor" href="#organization" aria-label="Permalink to &quot;Organization&quot;">​</a></h2><p>Basic information about your customer.</p><ul><li><strong>Name</strong> — editable.</li><li><strong>Billing Contact Email</strong> — receives billing-related notifications.</li><li><strong>Timezone</strong> — used for invoice period boundaries and report formatting.</li></ul><p>Click <strong>Edit</strong> to enter edit mode, change what you need, and <strong>Save</strong>.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><p><img src="'+e+'" alt="Portal Settings — Security tab" class="light-only"><img src="'+r+'" alt="Portal Settings — Security tab" class="dark-only"></p><p>The most consequential tab — your authentication policy lives here.</p><h3 id="password-policy" tabindex="-1">Password Policy <a class="header-anchor" href="#password-policy" aria-label="Permalink to &quot;Password Policy&quot;">​</a></h3><ul><li><strong>Minimum / maximum length</strong>.</li><li>Require <strong>uppercase</strong>, <strong>lowercase</strong>, <strong>numbers</strong>, <strong>symbols</strong> (each is a toggle).</li><li><strong>Expiration</strong> — how often passwords must be changed.</li></ul><p>These rules apply to anyone signing in with a password to your customer organisation. Updates take effect on the next password reset.</p><h3 id="mfa-policy" tabindex="-1">MFA Policy <a class="header-anchor" href="#mfa-policy" aria-label="Permalink to &quot;MFA Policy&quot;">​</a></h3><ul><li><strong>Enforce MFA</strong> — global toggle. When on, your users must enrol in MFA before they can sign in. When off, MFA is optional.</li><li><strong>Allowed MFA Methods</strong> — checkboxes for <strong>TOTP</strong> (authenticator app), <strong>Email OTP</strong>, <strong>SMS OTP</strong>, and <strong>Security Keys / Passkeys</strong>. Tick the ones you allow.</li></ul><h3 id="username-password" tabindex="-1">Username / Password <a class="header-anchor" href="#username-password" aria-label="Permalink to &quot;Username / Password&quot;">​</a></h3><ul><li><strong>Allow Username/Password</strong> — toggle. When off, your users must use an Identity Provider (Google, Microsoft, custom OIDC) to sign in. There is no password fallback in that case.</li></ul><h3 id="identity-providers" tabindex="-1">Identity Providers <a class="header-anchor" href="#identity-providers" aria-label="Permalink to &quot;Identity Providers&quot;">​</a></h3><p>A table of external IdPs your organisation has registered.</p><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Provider name</strong></td><td>Display label.</td></tr><tr><td><strong>Type</strong></td><td>Google / Azure / Custom OIDC.</td></tr><tr><td><strong>Client ID</strong></td><td>Truncated.</td></tr><tr><td><strong>Status</strong></td><td>Enabled / disabled.</td></tr><tr><td><strong>Actions</strong></td><td>Edit / Delete / Test.</td></tr></tbody></table><p>Click <strong>Add IdP</strong> to configure a new provider. The modal asks for:</p><ul><li><strong>Type</strong> — Google / Azure / custom OIDC.</li><li><strong>Name</strong> — what users see on the sign-in screen.</li><li><strong>Client ID</strong> and <strong>Client Secret</strong> — issued by the IdP.</li><li><strong>Azure Tenant ID</strong> — for Azure.</li><li><strong>Custom Scopes</strong> — for custom OIDC providers.</li></ul><p>After creation, the <strong>Test</strong> button performs a trial OIDC exchange so you can validate before enabling for users. Secrets are not displayed after creation — if you lose the secret you need to rotate it on the IdP side.</p><h2 id="service-accounts" tabindex="-1">Service Accounts <a class="header-anchor" href="#service-accounts" aria-label="Permalink to &quot;Service Accounts&quot;">​</a></h2><p>Machine identities for API and automation use.</p><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Account name</strong></td><td></td></tr><tr><td><strong>Created</strong></td><td></td></tr><tr><td><strong>Last used</strong></td><td></td></tr><tr><td><strong>Actions</strong></td><td>View / Copy secret, Revoke.</td></tr></tbody></table><p>Click <strong>Create</strong> to register a new service account. The secret is shown <strong>once</strong> at creation — copy it then. If you lose it, revoke the account and create a fresh one.</p><p>Under each service account, <strong>grants</strong> show which tenants and roles the account can act against.</p><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><p>Outbound HTTP endpoints subscribed to platform events.</p><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Endpoint URL</strong></td><td></td></tr><tr><td><strong>Event types</strong></td><td>Count subscribed.</td></tr><tr><td><strong>Status</strong></td><td>Enabled / disabled.</td></tr><tr><td><strong>Actions</strong></td><td>Edit / Test / Delete.</td></tr></tbody></table><p>Click <strong>Create</strong> to add a webhook. The modal asks for:</p><ul><li><strong>URL</strong> — your endpoint.</li><li><strong>Event types</strong> — multi-select of platform events.</li><li><strong>Auth headers</strong> — any custom headers to include on delivery (e.g. an API key).</li></ul><p>Per-webhook delivery history is shown so you can see retries and failures, and trigger redeliveries.</p><h2 id="user-attributes" tabindex="-1">User Attributes <a class="header-anchor" href="#user-attributes" aria-label="Permalink to &quot;User Attributes&quot;">​</a></h2><p>The list of custom profile fields available in your customer organisation. The set of attributes is defined platform-wide by Exto; you choose which to enable, in what order, and whether they are required.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Key</strong></td><td>The attribute&#39;s machine name. Read-only.</td></tr><tr><td><strong>Label</strong></td><td>The display label.</td></tr><tr><td><strong>Type</strong></td><td>text / number / select / multi_select / date / switch. Read-only.</td></tr><tr><td><strong>Required</strong></td><td>Toggle.</td></tr><tr><td><strong>Enabled</strong></td><td>Toggle.</td></tr><tr><td><strong>Order</strong></td><td>Display order.</td></tr></tbody></table><p>Enabled attributes appear on the Complete Profile flow for new users in your organisation and on their Account page for editing.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>The entire Settings page requires <code>manage_settings</code>. If you do not have it, the Settings entry will not appear in your sidebar.</p>',40)])])}const y=o(i,[["render",d]]);export{m as __pageData,y as default};
